import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.HG0H2VLS.js";const h=JSON.parse('{"title":"Select — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/Select/Select.figma-notes.md","filePath":"public/demos/src/components/Select/Select.figma-notes.md"}'),a={name:"public/demos/src/components/Select/Select.figma-notes.md"};function i(c,t,n,s,l,g){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="select-—-figma-notes" tabindex="-1">Select — Figma Notes <a class="header-anchor" href="#select-—-figma-notes" aria-label="Permalink to &quot;Select — Figma Notes&quot;">​</a></h1><p><strong>Figma URL:</strong> <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2527-1995" target="_blank" rel="noreferrer">node 2527:1995</a></p><h2 id="component-set" tabindex="-1">Component Set <a class="header-anchor" href="#component-set" aria-label="Permalink to &quot;Component Set&quot;">​</a></h2><p>Select is a Tier=Component design-system component for picking from a list of values. Five variant types covering single-select, multi-select list, disabled state, segmented category-region picker, and a minimal underline style. Triggers are rendered as <code>&lt;button&gt;</code> (not native <code>&lt;select&gt;</code>) so the value text remains visible in Figma capture.</p><h2 id="variant-×-size-matrix" tabindex="-1">Variant × Size Matrix <a class="header-anchor" href="#variant-×-size-matrix" aria-label="Permalink to &quot;Variant × Size Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node</th><th>Type</th><th>Size</th><th>Notes</th></tr></thead><tbody><tr><td><code>2527:1994</code></td><td>Default</td><td>Default</td><td>Bordered button trigger, value text + chevron</td></tr><tr><td><code>2527:1996</code></td><td>Default</td><td>sm</td><td>32px height, smaller font</td></tr><tr><td><code>2527:1993</code></td><td>Multiselect</td><td>Default</td><td>List view — selected items highlighted with <code>--ai-surface-minimal</code> bg + medium font weight</td></tr><tr><td><code>2527:1992</code></td><td>Disabled</td><td>Default</td><td>Greyed bg, muted text, not interactive</td></tr><tr><td><code>2527:2004</code></td><td>Disabled</td><td>sm</td><td>Smaller disabled</td></tr><tr><td><code>2527:1990</code></td><td>Category Dropdown</td><td>Default</td><td>Segmented — flag + country (left) + region select (right)</td></tr><tr><td><code>2527:2012</code></td><td>Category Dropdown</td><td>sm</td><td>Smaller segmented</td></tr><tr><td><code>2527:1991</code></td><td>Underline</td><td>Default</td><td>Bottom border only, transparent bg, no horizontal padding</td></tr></tbody></table><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma property</th><th>CSS class</th></tr></thead><tbody><tr><td>Type=Default</td><td><code>.sel__control</code></td></tr><tr><td>Type=Disabled</td><td><code>.sel__control</code> + <code>disabled</code> attr (or <code>.sel__control--disabled</code>)</td></tr><tr><td>Type=Underline</td><td><code>.sel__control.sel__control--underline</code></td></tr><tr><td>Type=Multiselect</td><td><code>.sel__list</code> (replaces button trigger)</td></tr><tr><td>Type=Category Dropdown</td><td><code>.sel-category</code> (with <code>.sel-category__category</code> + <code>.sel-category__value</code>)</td></tr><tr><td>Size=Default</td><td><code>.sel__control</code> (base)</td></tr><tr><td>Size=sm</td><td><code>.sel__control.sel__control--sm</code> (button) or <code>.sel-category--sm</code> (category)</td></tr><tr><td>Multiselect item selected</td><td><code>.sel__list-item--selected</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Value</th></tr></thead><tbody><tr><td>Trigger bg</td><td><code>--ai-surface-primary</code></td><td>#ffffff</td></tr><tr><td>Trigger border</td><td><code>--ai-border-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Trigger radius</td><td><code>--ai-radius-md</code></td><td>8px</td></tr><tr><td>Trigger height (Default)</td><td><code>--ai-spacing-8</code></td><td>40px</td></tr><tr><td>Trigger height (sm)</td><td><code>--ai-spacing-7</code></td><td>32px</td></tr><tr><td>Trigger padding-left (Default)</td><td><code>--ai-spacing-5</code></td><td>16px</td></tr><tr><td>Trigger padding-left (sm)</td><td><code>--ai-spacing-4</code></td><td>12px</td></tr><tr><td>Trigger padding-right (Default)</td><td><code>--ai-spacing-4</code></td><td>12px</td></tr><tr><td>Trigger padding-right (sm)</td><td><code>--ai-spacing-3</code></td><td>8px</td></tr><tr><td>Trigger gap</td><td><code>--ai-spacing-3</code></td><td>8px</td></tr><tr><td>Hover/focus border</td><td><code>--ai-border-brand</code></td><td>#0071d8</td></tr><tr><td>Focus halo</td><td><code>--ai-surface-brand-contrast</code></td><td>brand contrast</td></tr><tr><td>Label font</td><td><code>--ai-font-title</code> semibold + <code>--ai-font-fixed-xs</code></td><td>Inter 600 / 14px</td></tr><tr><td>Value font (Default)</td><td><code>--ai-font-title</code> regular + <code>--ai-font-fixed-xs</code></td><td>Inter 400 / 14px</td></tr><tr><td>Value font (sm)</td><td><code>--ai-font-title</code> regular + <code>--ai-font-fixed-xxs</code></td><td>Inter 400 / 12px</td></tr><tr><td>Value color</td><td><code>--ai-text-primary</code></td><td>#212123</td></tr><tr><td>Disabled bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Disabled text</td><td><code>--ai-text-contrast</code></td><td>#67676c</td></tr><tr><td>Underline border</td><td><code>--ai-border-secondary</code> (2px)</td><td>grey</td></tr><tr><td>Underline hover</td><td><code>--ai-border-brand</code> (2px)</td><td>brand blue</td></tr><tr><td>Multiselect list padding</td><td><code>--ai-spacing-2</code></td><td>6px</td></tr><tr><td>Multiselect item padding</td><td><code>--ai-spacing-2</code> v / <code>--ai-spacing-3</code> h</td><td>6/8px</td></tr><tr><td>Multiselect item radius</td><td><code>--ai-radius-sm</code></td><td>4px</td></tr><tr><td>Multiselect item height</td><td><code>--ai-spacing-8</code></td><td>40px (<code>min-height</code>)</td></tr><tr><td>Multiselect item gap</td><td><code>1px</code></td><td>spacing/px (raw)</td></tr><tr><td>Multiselect selected bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Multiselect selected weight</td><td><code>--ai-font-medium</code></td><td>500</td></tr><tr><td>Category divider</td><td><code>--ai-border-secondary</code> (1px right)</td><td>grey</td></tr><tr><td>Category bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Category hover bg</td><td><code>--ai-surface-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Category flag font</td><td><code>--ai-font-fixed-md</code></td><td>18px</td></tr><tr><td>Chevron icon size</td><td><code>--ai-icon-size-sm</code></td><td>16px</td></tr><tr><td>Chevron color</td><td><code>--ai-icon-contrast</code></td><td>#929295</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None. The 1px gap between Multiselect items and 2px Underline border are optical units per CLAUDE rules.</p><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Lucide name</th></tr></thead><tbody><tr><td>Trigger / category chevron</td><td><code>chevron-down</code></td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><p>None — Select is self-contained. No native <code>&lt;select&gt;</code> element used (button-based triggers display the value as visible HTML text so it captures correctly to Figma).</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Triggers are <code>&lt;button&gt;</code> elements rather than native <code>&lt;select&gt;</code>. Native selects don&#39;t render their selected option as visible text in Figma&#39;s html-to-design capture, so the chosen value would appear as an empty box. Buttons + a <code>&lt;span class=&quot;sel__value&quot;&gt;</code> keeps the value visible and capturable. Production wiring would connect this to a popover dropdown; the prototype shows the trigger only.</li><li>Country flags use emoji (🇬🇧). For higher-fidelity rendering swap for SVG flags in production.</li><li>Multiselect is shown in its open/list state. In production a multiselect would also have a button trigger that opens this list — same <code>.sel__list</code> rendered in a popover.</li><li>Underline variant has no horizontal padding so the value aligns flush-left with the parent surface (matches Figma where pl/pr are 0).</li><li>Disabled <code>:hover</code> is suppressed (<code>border-color: --ai-border-secondary</code>) to override the brand-border hover.</li></ul>',18)])])}const u=e(a,[["render",i]]);export{h as __pageData,u as default};
